mapper.select:
select c.id, c.title, c.description, c.cover_image, c.price, c.level, c.student_count, c.create_time, -- 平均分：IFNULL:没有评分的时候放回0，ROUND:保留1位小数更友好 ROUND(IFNULL(AVG(cc.rating), 0), 1) as cc.rating from courses c -- 左关联评分表，保证无评分的课程也能查询出来 left join course_comments cc on c.id = cc.course_id
c.title like concat('%',#{title},'%')
and c.category_id = #{categoryId}
and c.status = #{status}
-- 按课程ID分组，否则聚合函数会把所有课程的评分算成一个平均值 group by c.id
